const Layer = require('express/lib/router/layer');
const Router = require('express/lib/router');

const last = (arr = []) => arr[arr.length - 1];
const noop = Function.prototype;

function copyFnProps(oldFn, newFn) {
  Object.keys(oldFn).forEach((key) => {
    newFn[key] = oldFn[key];
  });
  return newFn;
}

function wrap(fn) {
  const newFn = function newFn(...args) {
    const ret = fn.apply(this, args);
    const next = (args.length === 5 ? args[2] : last(args)) || noop;
    if (ret && ret.catch) ret.catch(err => next(err));
    return ret;
  };
  Object.defineProperty(newFn, 'length', {
    value: fn.length,
    writable: false,
  });
  return copyFnProps(fn, newFn);
}

function patchRouterParam() {
  const originalParam = Router.prototype.constructor.param;
  Router.prototype.constructor.param = function param(name, fn) {
    fn = wrap(fn);
    return originalParam.call(this, name, fn);
  };
}

Object.defineProperty(Layer.prototype, 'handle', {
  enumerable: true,
  get() {
    return this.__handle;
  },
  set(fn) {
    fn = wrap(fn);
    this.__handle = fn;
  },
});

patchRouterParam();

import { ErrorMessage, FieldMessageFactory, InternalRequest, Location } from '../base';
import {
  ContextHandlerImpl,
  ContextRunnerImpl,
  SanitizersImpl,
  ValidationChain,
  ValidatorsImpl,
} from '../chain';
import { ContextBuilder } from '../context-builder';
import { bindAll } from '../utils';

export function check(
  fields: string | string[] = '',
  locations: Location[] = [],
  message?: FieldMessageFactory | ErrorMessage,
): ValidationChain {
  const builder = new ContextBuilder()
    .setFields(Array.isArray(fields) ? fields : [fields])
    .setLocations(locations)
    .setMessage(message);
  const runner = new ContextRunnerImpl(builder);

  const middleware = async (req: InternalRequest, _res: any, next: (err?: any) => void) => {
    try {
      await runner.run(req);
      next();
    } catch (e) {
      next(e);
    }
  };

  return Object.assign(
    middleware,
    bindAll(runner),
    bindAll(new SanitizersImpl(builder, middleware as any)),
    bindAll(new ValidatorsImpl(builder, middleware as any)),
    bindAll(new ContextHandlerImpl(builder, middleware as any)),
    { builder },
  );
}

const safePromisify = require('../../utils/promisifyCompat');
const { get: getClient } = require('../../client');

// Default hook that checks if the user has been logged out via Back-Channel Logout
module.exports = async (req, config) => {
  const store =
    (config.backchannelLogout && config.backchannelLogout.store) ||
    config.session.store;
  const get = safePromisify(store.get, store);
  const { serverMetadata } = await getClient(config);
  const issuer = serverMetadata.issuer;
  const { sid, sub } = req.oidc.idTokenClaims;
  if (!sid && !sub) {
    throw new Error(`The session must have a 'sid' or a 'sub'`);
  }
  const [logoutSid, logoutSub] = await Promise.all([
    sid && get(`${issuer}|${sid}`),
    sub && get(`${issuer}|${sub}`),
  ]);
  return !!(logoutSid || logoutSub);
};

